window.BCS_STUDY=window.BCS_STUDY||{version:'2026.07',subjects:{}};Object.assign(window.BCS_STUDY.subjects,{"mental":{"title":"মানসিক দক্ষতা","modules":[{"id":"mental-series","title":"সংখ্যা ও বর্ণের ধারা","intro":"পার্থক্য, অনুপাত, পর্যায়ক্রমিক pattern এবং অবস্থান পরিবর্তন খুঁজে দ্রুত পরবর্তী পদ নির্ণয় করুন।","points":["প্রথমে consecutive difference দেখুন; না মিললে second difference পরীক্ষা করুন।","গুণ/ভাগ pattern এবং alternating দুইটি sequence আলাদা করে দেখুন।","বর্ণমালার অবস্থান A=1, B=2 ব্যবহার করে jump pattern বের করুন।","Square, cube, prime ও Fibonacci-জাতীয় পরিচিত ধারা চিনুন।","একাধিক সম্ভাবনা থাকলে সব পদের সঙ্গে যে নিয়ম সামঞ্জস্যপূর্ণ সেটি নিন।"],"focus":["Difference table","Alternating series","Letter position"],"sources":[{"title":"BCS Preliminary Mental Ability Pattern","url":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"title":"OpenStax Algebra and Problem Solving","url":"https://openstax.org/books/elementary-algebra-2e/pages/1-introduction"}]},{"id":"mental-analogy","title":"Analogy ও Classification","intro":"দুটি শব্দ বা ধারণার সম্পর্ক নির্ধারণ করে একই সম্পর্কের জোড়া এবং ব্যতিক্রমী item শনাক্ত করুন।","points":["সম্পর্ক হতে পারে বস্তু–ব্যবহার, প্রাণী–বাসস্থান, অংশ–সমগ্র, কারণ–ফল বা মাত্রা।","Synonym ও antonym relation গুলিয়ে ফেলবেন না।","Classification-এ একই শ্রেণির তিনটির মধ্যে ভিন্ন বৈশিষ্ট্যের item খুঁজুন।","শব্দের বাহ্যিক মিল নয়, কার্যকর অর্থগত সম্পর্ক প্রাধান্য পায়।","Analogy বাক্যে প্রকাশ করলে relation স্পষ্ট হয়: Bird lives in nest; bee lives in hive."],"focus":["Relation naming","Odd-one-out justification","Verbal analogy"],"sources":[{"title":"BCS Preliminary Mental Ability Pattern","url":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"title":"OpenStax Algebra and Problem Solving","url":"https://openstax.org/books/elementary-algebra-2e/pages/1-introduction"}]},{"id":"mental-direction","title":"দিক, ক্রম ও স্থানিক যুক্তি","intro":"Diagram এঁকে direction, seating, rank এবং movement সমস্যায় ভুল কমান।","points":["উত্তরকে উপরে ধরে ডানদিকে ঘড়ির কাঁটার দিক; বামদিকে বিপরীত ঘূর্ণন।","দুটি right turn মোট 180° ঘূর্ণন।","Rank problem-এ মোট = বাম থেকে rank + ডান থেকে rank − 1.","Seating arrangement-এ নিশ্চিত তথ্য আগে বসিয়ে relative relation যোগ করুন।","Mirror ও rotation সমস্যায় orientation পর্যবেক্ষণ করুন, শুধু position নয়।"],"focus":["Compass sketch","Ranking formula","Seating grid"],"sources":[{"title":"BCS Preliminary Mental Ability Pattern","url":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"title":"OpenStax Algebra and Problem Solving","url":"https://openstax.org/books/elementary-algebra-2e/pages/1-introduction"}]},{"id":"mental-logic","title":"যুক্তি, অনুমান ও সমস্যা সমাধান","intro":"Statement থেকে শুধু অনিবার্য conclusion নিন; বাস্তব জ্ঞান বা অনুমান যোগ করবেন না।","points":["All A are B থেকে সব B যে A—এ সিদ্ধান্ত আসে না।","Some A are B অস্তিত্ব নির্দেশ করে; No A is B সম্পূর্ণ বিচ্ছিন্নতা নির্দেশ করে।","Necessary condition না থাকলে ফল অসম্ভব; sufficient condition থাকলে ফল নিশ্চিত।","Data sufficiency-তে answer বের করা নয়, তথ্য যথেষ্ট কি না বিচার করা হয়।","Complex problem ছোট ধাপে ভাগ করে constraint লিখলে সমাধান সহজ হয়।"],"focus":["Syllogism diagram","Necessary বনাম sufficient","Constraint table"],"sources":[{"title":"BCS Preliminary Mental Ability Pattern","url":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"title":"OpenStax Algebra and Problem Solving","url":"https://openstax.org/books/elementary-algebra-2e/pages/1-introduction"}]}]},"ethics":{"title":"নৈতিকতা, মূল্যবোধ ও সুশাসন","modules":[{"id":"ethics-values","title":"নৈতিকতা ও মূল্যবোধের ভিত্তি","intro":"নৈতিক নীতি, ব্যক্তিগত মূল্যবোধ, কর্তব্য, ফল এবং গুণনৈতিকতার মৌলিক পার্থক্য বুঝুন।","points":["Ethics সঠিক-ভুল আচরণের যুক্তিনির্ভর আলোচনা; value ব্যক্তি বা সমাজের গুরুত্বপূর্ণ আদর্শ।","Duty-based reasoning কাজের নীতি ও কর্তব্য দেখে; consequence-based reasoning ফল মূল্যায়ন করে।","Virtue ethics সততা, সাহস, সংযম ও ন্যায়পরায়ণতার মতো চরিত্রগুণে জোর দেয়।","Ethical dilemma-তে দুই বা ততোধিক নৈতিক কর্তব্য বা মূল্যবোধ সংঘর্ষে আসে।","আইন মানা ন্যূনতম বাধ্যবাধকতা; নৈতিকতা অনেক সময় আইনের চেয়ে উচ্চতর মান দাবি করে।"],"focus":["নৈতিক তত্ত্বের তুলনা","Dilemma বিশ্লেষণ","মূল্যবোধের বাস্তব উদাহরণ"],"sources":[{"title":"Bangladesh Constitution","url":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"title":"World Bank Worldwide Governance Indicators","url":"https://www.worldbank.org/en/publication/worldwide-governance-indicators"}]},{"id":"ethics-governance","title":"সুশাসনের উপাদান","intro":"Participation, rule of law, transparency, accountability, effectiveness, equity এবং corruption control সুশাসনের কেন্দ্রীয় ধারণা।","points":["Rule of law-এ আইন সবার জন্য প্রযোজ্য এবং স্বাধীন বিচার ও ন্যায্য প্রক্রিয়া গুরুত্বপূর্ণ।","Transparency সিদ্ধান্ত, তথ্য ও প্রক্রিয়ার দৃশ্যমানতা বাড়ায়।","Accountability-তে সিদ্ধান্তদাতাকে ব্যাখ্যা দিতে ও ফলের দায় নিতে হয়।","Participation নাগরিকের মতামত ও মালিকানা বাড়ায়; inclusion প্রান্তিক গোষ্ঠীর সুযোগ নিশ্চিত করে।","World Bank WGI ছয়টি dimension ব্যবহার করে, তবে এগুলো composite perception indicators."],"focus":["সুশাসনের উপাদান","Transparency বনাম accountability","WGI dimensions"],"sources":[{"title":"Bangladesh Constitution","url":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"title":"World Bank Worldwide Governance Indicators","url":"https://www.worldbank.org/en/publication/worldwide-governance-indicators"}]},{"id":"ethics-public","title":"জনসেবা, সততা ও স্বার্থের সংঘাত","intro":"Public interest, impartiality, integrity, confidentiality এবং conflict of interest-এর ব্যবহারিক প্রয়োগ শিখুন।","points":["Integrity মানে কথিত নীতি ও বাস্তব আচরণের সামঞ্জস্য।","Impartiality ব্যক্তিগত সম্পর্ক, রাজনৈতিক পছন্দ বা পক্ষপাত ছাড়া একই মানদণ্ড প্রয়োগ।","Conflict of interest-এ ব্যক্তিগত স্বার্থ দাপ্তরিক সিদ্ধান্তকে প্রভাবিত করতে পারে বা এমন ধারণা তৈরি করে।","Confidentiality গুরুত্বপূর্ণ, তবে বেআইনি কাজ গোপন করার অজুহাত নয়।","Whistleblowing যথাযথ channel-এ গুরুতর অনিয়ম রিপোর্ট করা; প্রমাণ ও জনস্বার্থ গুরুত্বপূর্ণ।"],"focus":["Conflict scenario","Public interest test","Integrity ও impartiality"],"sources":[{"title":"Bangladesh Constitution","url":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"title":"World Bank Worldwide Governance Indicators","url":"https://www.worldbank.org/en/publication/worldwide-governance-indicators"}]},{"id":"ethics-rights","title":"মানবাধিকার ও সাংবিধানিক নৈতিকতা","intro":"মানব মর্যাদা, সমতা, স্বাধীনতা, ন্যায়বিচার এবং অধিকার-দায়িত্বের ভারসাম্য নৈতিক সিদ্ধান্তের ভিত্তি।","points":["UDHR ঘোষণা করে মানুষ মর্যাদা ও অধিকারে স্বাধীন ও সমান জন্মগ্রহণ করে।","সমতা মানে সব ক্ষেত্রে যান্ত্রিক একই আচরণ নয়; ন্যায্যতা প্রাসঙ্গিক বৈষম্য বিবেচনা করতে পারে।","অধিকারের সঙ্গে অন্যের অধিকার ও জনকল্যাণের প্রতি দায়িত্ব যুক্ত।","বাংলাদেশের সংবিধানে আইনের দৃষ্টিতে সমতা ও বৈষম্যবিরোধী নীতি রয়েছে।","Due process ও impartial hearing ন্যায়বিচারের গুরুত্বপূর্ণ উপাদান।"],"focus":["UDHR core rights","Equality বনাম equity","Rights–duties balance"],"sources":[{"title":"Bangladesh Constitution","url":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"title":"World Bank Worldwide Governance Indicators","url":"https://www.worldbank.org/en/publication/worldwide-governance-indicators"}]}]}});(()=>{'use strict';const d=window.BCS_DATA,s=Math.max(0,...d.questions.map(q=>Number(q.id)||0))+1,r=[{"subject":"mental","topicId":"mental-series","study":true,"question":"2, 4, 8, 16, ?","options":["24","32","30","36"],"answer":1,"explanation":"প্রতিটি পদ দ্বিগুণ; পরের পদ 32।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-series","study":true,"question":"3, 6, 11, 18, 27, ?","options":["34","36","38","40"],"answer":2,"explanation":"পার্থক্য 3,5,7,9; পরের পার্থক্য 11, তাই 38।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-series","study":true,"question":"A, C, F, J, O, ?","options":["T","U","V","W"],"answer":1,"explanation":"Jump +2,+3,+4,+5; next +6, O→U।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-analogy","study":true,"question":"Bird : Nest :: Bee : ?","options":["Hive","Water","Grass","Book"],"answer":0,"explanation":"বাসস্থান সম্পর্ক: bird–nest, bee–hive।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-analogy","study":true,"question":"Book : Reading :: Fork : ?","options":["Writing","Eating","Walking","Sleeping"],"answer":1,"explanation":"ব্যবহার সম্পর্ক: book for reading, fork for eating।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-analogy","study":true,"question":"Odd one out: Triangle, Square, Circle, Cube","options":["Triangle","Square","Circle","Cube"],"answer":3,"explanation":"Cube ত্রিমাত্রিক; অন্যগুলো দ্বিমাত্রিক।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-direction","study":true,"question":"উত্তরমুখী ব্যক্তি দুইবার ডানে ঘুরলে কোনদিকে মুখ করবে?","options":["উত্তর","দক্ষিণ","পূর্ব","পশ্চিম"],"answer":1,"explanation":"North→East→South।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-direction","study":true,"question":"বাম থেকে 8ম ও ডান থেকে 5ম হলে মোট কতজন?","options":["11","12","13","14"],"answer":1,"explanation":"8+5−1=12।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-direction","study":true,"question":"পূর্বমুখী ব্যক্তি বামে ঘুরলে কোনদিকে?","options":["উত্তর","দক্ষিণ","পশ্চিম","পূর্ব"],"answer":0,"explanation":"East থেকে left turn করলে North।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-logic","study":true,"question":"All roses are flowers. কোন সিদ্ধান্ত নিশ্চিত?","options":["All flowers are roses","All roses are flowers","No flower is a rose","Some flowers are not plants"],"answer":1,"explanation":"Premise-টি সরাসরি নিশ্চিত করে সব rose flower।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-logic","study":true,"question":"Necessary condition বলতে কী বোঝায়?","options":["যা ছাড়া ফল সম্ভব নয়","যা থাকলেই সবসময় ফল নিশ্চিত","শুধু অনুমান","অপ্রাসঙ্গিক তথ্য"],"answer":0,"explanation":"Necessary condition অনুপস্থিত হলে ফল ঘটতে পারে না।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"mental","topicId":"mental-logic","study":true,"question":"Some A are B থেকে কোনটি নিশ্চিত?","options":["অন্তত একটি A একই সঙ্গে B","সব A হলো B","কোনো A B নয়","সব B হলো A"],"answer":0,"explanation":"‘Some’ অন্তত একটি overlap নির্দেশ করে।","sourceUrl":"https://bpsc.gov.bd/pages/static-pages/691997b3933eb65569dde2bf"},{"subject":"ethics","topicId":"ethics-values","study":true,"question":"Ethical dilemma কী?","options":["নৈতিক মূল্যবোধের সংঘর্ষে কঠিন পছন্দ","সহজ হিসাব","শুধু আইনি নথি","কোনো বিকল্প নেই"],"answer":0,"explanation":"দুটি বা বেশি নৈতিক কর্তব্য/মূল্য সংঘর্ষে এলে dilemma হয়।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-values","study":true,"question":"Virtue ethics কী গুরুত্ব দেয়?","options":["চরিত্রগুণ","শুধু শাস্তি","শুধু লাভ","শুধু ভোট"],"answer":0,"explanation":"Virtue ethics সততা, সাহস, সংযম ইত্যাদি চরিত্রগুণে জোর দেয়।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-values","study":true,"question":"আইন ও নৈতিকতার সম্পর্ক কী?","options":["নৈতিকতা কখনও আইনের চেয়ে উচ্চ মান দাবি করতে পারে","দুটি সবসময় অভিন্ন","আইনের কোনো মূল্য নেই","নৈতিকতা শুধু ব্যক্তিগত পছন্দ"],"answer":0,"explanation":"আইন ন্যূনতম বাধ্যবাধকতা হতে পারে; নৈতিকতা আরও বিস্তৃত দায়িত্ব দাবি করে।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-governance","study":true,"question":"Transparency কী বাড়ায়?","options":["তথ্য ও প্রক্রিয়ার দৃশ্যমানতা","গোপন সিদ্ধান্ত","পক্ষপাত","দায়মুক্তি"],"answer":0,"explanation":"স্বচ্ছতা সিদ্ধান্ত ও তথ্য নাগরিকের কাছে দৃশ্যমান করে।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-governance","study":true,"question":"Accountability-এর অর্থ কী?","options":["সিদ্ধান্তের ব্যাখ্যা ও দায় গ্রহণ","তথ্য লুকানো","শুধু দ্রুততা","কোনো জবাব না দেওয়া"],"answer":0,"explanation":"Accountability-তে answerability ও consequence থাকে।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-governance","study":true,"question":"কোনটি World Bank WGI dimension?","options":["Rule of Law","Planetary Motion","Cell Biology","Poetic Meter"],"answer":0,"explanation":"Rule of Law WGI-এর ছয় dimension-এর একটি।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-public","study":true,"question":"Conflict of interest কখন ঘটে?","options":["ব্যক্তিগত স্বার্থ দাপ্তরিক সিদ্ধান্তকে প্রভাবিত করতে পারে","সবাই একই মত হলে","আইন প্রকাশ করলে","ছুটি নিলে"],"answer":0,"explanation":"Personal interest official judgment-কে প্রভাবিত বা প্রভাবিত বলে মনে করাতে পারে।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-public","study":true,"question":"Impartiality কী?","options":["পক্ষপাতহীনভাবে একই মানদণ্ড প্রয়োগ","পরিচিতকে সুবিধা","তথ্য গোপন","শুধু আনুগত্য"],"answer":0,"explanation":"Impartiality ব্যক্তিগত পক্ষপাত ছাড়া ন্যায্য আচরণ।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-public","study":true,"question":"Whistleblowing কী?","options":["যথাযথ channel-এ গুরুতর অনিয়ম রিপোর্ট","গুজব ছড়ানো","গোপন নথি বিক্রি","দায়িত্ব এড়ানো"],"answer":0,"explanation":"Evidence-based wrongdoing report public interest-এ whistleblowing হতে পারে।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-rights","study":true,"question":"UDHR-এর Article 1-এর মূল ভাব কী?","options":["মানুষ মর্যাদা ও অধিকারে স্বাধীন ও সমান","কেবল রাষ্ট্রের অধিকার আছে","মতপ্রকাশ নিষিদ্ধ","শিক্ষা অপ্রয়োজনীয়"],"answer":0,"explanation":"Article 1 human dignity ও equality ঘোষণা করে।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-rights","study":true,"question":"Equality ও equity-এর পার্থক্য কী?","options":["Equity প্রাসঙ্গিক প্রয়োজন বিবেচনা করে ন্যায্যতা আনে","দুটি সম্পূর্ণ বিপরীত","Equality মানে বৈষম্য","Equity মানে পক্ষপাত"],"answer":0,"explanation":"Equity ভিন্ন পরিস্থিতিতে ন্যায্য ফলের জন্য প্রয়োজনমাফিক সহায়তা বিবেচনা করে।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"},{"subject":"ethics","topicId":"ethics-rights","study":true,"question":"Due process-এর কেন্দ্রীয় উপাদান কোনটি?","options":["ন্যায্য ও নিরপেক্ষ শুনানি","গোপন শাস্তি","প্রমাণ ছাড়া সিদ্ধান্ত","একতরফা বিচার"],"answer":0,"explanation":"Fair and impartial process ন্যায়বিচারের মৌলিক অংশ।","sourceUrl":"https://bdlaws.minlaw.gov.bd/act-print-367.html"}];d.questions.push(...r.map((q,i)=>({...q,id:s+i})));})();